+            else {
+                *pma = nxt;
+                int isaligned = (uintptr_t)ma->a & 1;
+                jl_gc_free_memory(a, isaligned);
+                ma->next = ptls2->gc_tls_common.heap.mafreelist;
+                ptls2->gc_tls_common.heap.mafreelist = ma;
+            }
+            ma = nxt;
+        }
+        ptls2 = (jl_ptls_t)mmtk_get_next_mutator_tls(iter);
+    }
